/// <summary>
/// Determines if concurrent deletes should throw exception.
/// </summary>
/// <returns>true, if exception should be thrown; otherwise, false.</returns>
public boolean shouldThrowExceptionOnZeroDelete()
{
    return true;
}

public static void populate(UserId _userId = '')
{
    DEVLicenseReportUserPermission              licenseReportUserPermission;
    LicensingRolePermissions                    licensingRolePermissions;
    LicensingUserLicensesByRole                 licensingUserLicensesByRole;

    boolean filterByUser = (_userId != '');

    // 1) Delete existing records (all, or just for the user if filter provided)
    ttsbegin;

    if (!filterByUser)
    {
        delete_from licenseReportUserPermission;
    }
    else
    {
        delete_from licenseReportUserPermission
            where licenseReportUserPermission.UserId == _userId;
    }

    ttscommit;

    // 2) Insert aggregated rows using insert_recordset
    ttsbegin;

    insert_recordset licenseReportUserPermission (EntitlementObject, AccessLevel, UserId)
    select  EntitlementObject, maxof(AccessLevel)
        from licensingRolePermissions
        group by licensingUserLicensesByRole.UserId,            licensingRolePermissions.EntitlementObject
        join UserId from licensingUserLicensesByRole
            where licensingUserLicensesByRole.SecurityRoleRecId == licensingRolePermissions.SecurityRole &&
        ( (filterByUser ? false : true) || licensingUserLicensesByRole.UserId == _userId) ;


    ttscommit;
}
